import requests

def fetch_film_metadata(film_title):
    # Hypothetical API endpoint
    api_url = f"https://api.filmdatabase.com/v1/search?title={film_title}"
    response = requests.get(api_url)
    if response.status_code == 200:
        return response.json()
    else:
        return {"error": "Failed to fetch data"}

# Example usage
metadata = fetch_film_metadata("Divine Horsemen: The Living Gods of Haiti")
print(metadata)
